def moving_average(nums, k):
    if not nums or k > len(nums):
        return []
    window_sum = sum(nums[:k])
    result = [round(window_sum / k, 2)]
    for i in range(k, len(nums)):
        window_sum += nums[i] - nums[i - k]
        result.append(round(window_sum / k, 2))
